impl Solution { pub fn minimum_operations(nums: Vec<i32>, start: i32, goal: i32) -> i32 { let (mut black_q, mut black_vis) = (std::collections::VecDeque::from([(start, 0)]), vec![false; 1001]); while let Some((x, d)) = black_q.pop_front() { if x == goal { return d; } if x < 0 || x > 1000 || black_vis[x as usize] { continue; } black_vis[x as usize] = true; for &n in &nums { for &next in &[x + n, x - n, x ^ n] { black_q.push_back((next, d + 1)); } } } -1 } }